
import {
  defineComponent,
  provide,
  reactive,
  ref,
  toRefs,
  watch,
} from "vue";
import { useRouter } from "vue-router";
import AmultitaskingSearch from "../../../components/Amultitasking/AmultitaskingSearch.vue";
import AmultitaskingTable from "../../../components/Amultitasking/AmultitaskingTable.vue";
import { getTaskInfo } from "../../../server/http/api/Amultitasking";
export default defineComponent({
  name: "Taskacceptance",
  components: { AmultitaskingSearch, AmultitaskingTable },
  setup() {
    //===============条件查询====================
    let dataList: any = ref([]);
    let formState: any = {};
    const total = ref(0);
    let options = reactive({
      pageNum: 1,
      pageSize: 10,
    });
    function init() {
      getTaskInfo(formState).then((res: any) => {
        if (res.data.code === 200) {
          dataList.value = res.data.data.list;
          total.value = res.data.data.total;
        }
      });
    }
    function filterTaskacceptance(form: any) {
      Object.assign(formState, form);
      Object.assign(formState, options);
      init();
    }
    watch(options, () => {
      Object.assign(formState, options);

      init();
    });
    //==========================================
    // 任务详情
    const router = useRouter();
    function detailClick(id: number) {
      router.push({ name: "TaskacceptanceDetail", params: { id } });
    }
    provide("init", init);

    return {
      filterTaskacceptance,
      dataList,
      detailClick,
      total,
      ...toRefs(options),
      formState,
      init,
    };
  },
});
